('constitutional', 'constitution', 'საქართველოს კონსტიტუციის მიხედვით, რა ვალდებულება აქვთ კონსტიტუციურ ორგანოებს ევროპულ და ევროატლანტიკურ სტრუქტურებში ინტეგრაციის მიმართულებით?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს კონსტიტუციის მუხლი 78 ადგენს, რომ კონსტიტუციურმა ორგანოებმა თავიანთი უფლებამოსილების ფარგლებში უნდა მიიღონ ყველა ზომა ევროპის კავშირსა და ჩრდილოატლანტიკური ხელშეკრულების ორგანიზაციაში საქართველოს სრული ინტეგრაციის უზრუნველსაყოფად.', 'საქართველოს კონსტიტუცია', 'მუხლი 78', '', '2018-03-23', false, 'შეაჩერონ ყველა საერთაშორისო თანამშრომლობა', 'მიიღონ ყველა ზომა ევროკავშირსა და ნატოში სრული ინტეგრაციის უზრუნველსაყოფად', 'მხოლოდ ადგილობრივი თვითმმართველობის გაერთიანებები შექმნან', 'მხოლოდ საბიუჯეტო ანგარიშები წარადგინონ', 'B'),
('constitutional', 'constitution', 'საქართველოს კონსტიტუციის მიხედვით, რომელი პირი კარგავს პოლიტიკური პარტიის წევრობას მისი თანამდებობრივი სტატუსის გამო?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს კონსტიტუციის მუხლი 23 ადგენს, რომ თავდაცვის ძალების ან სახელმწიფო ან საზოგადოებრივი უსაფრთხოების დაცვაზე პასუხისმგებელი ორგანოს შემადგენლობაში ჩარიცხულ პირს, აგრეთვე მოსამართლედ განწესებულ პირს, უწყდება პოლიტიკური პარტიის წევრობა.', 'საქართველოს კონსტიტუცია', 'მუხლი 23', '', '2018-03-23', false, 'მხოლოდ მუნიციპალიტეტის საკრებულოს წევრი', 'მხოლოდ არასამთავრობო ორგანიზაციის წევრი', 'მოსამართლედ განწესებული ან უსაფრთხოების ორგანოში ჩარიცხული პირი', 'მხოლოდ კერძო კომპანიის დირექტორი', 'C');

do $$
declare
  v_category_id uuid;
  v_subcategory_id uuid;
  v_law_id uuid;
  v_question_id uuid;
  v_article_id uuid;
  v_meta record;
  r record;
begin
  select * into v_meta from question_import_staging_full limit 1;

  insert into public.categories(slug, title, description, sort_order, is_active)
  values (v_meta.category_slug, v_meta.law_name, v_meta.law_name, 5, true)
  on conflict (slug) do update
  set title = excluded.title,
      description = excluded.description,
      is_active = true
  returning id into v_category_id;

  insert into public.subcategories(category_id, title, slug)
  values (v_category_id, v_meta.law_name, v_meta.subcategory_slug)
  on conflict (category_id, slug) do update
  set title = excluded.title
  returning id into v_subcategory_id;

  insert into public.laws(slug, title, short_title, direction_slug, description, current_version_date, is_active, needs_review, sort_order)
  values ('constitution-of-georgia', v_meta.law_name, v_meta.law_name, v_meta.category_slug, v_meta.law_name, nullif(v_meta.law_version_date, '')::date, true, false, 10)
  on conflict (slug) do update
  set title = excluded.title,
      short_title = excluded.short_title,
      direction_slug = excluded.direction_slug,
      description = excluded.description,
      current_version_date = excluded.current_version_date,
      is_active = true,
      needs_review = false
  returning id into v_law_id;

  for r in select * from question_import_staging_full loop
    insert into public.law_articles(law_id, article_number, version_date, is_active)
    values (v_law_id, r.law_article, nullif(r.law_version_date, '')::date, true)
    on conflict (law_id, article_number) do update
    set version_date = excluded.version_date,
        is_active = true
    returning id into v_article_id;

    select q.id into v_question_id
    from public.questions q
    where q.law_id = v_law_id and q.text = r.text
    limit 1;

    if v_question_id is null then
      insert into public.questions(
        category_id, subcategory_id, text, difficulty, explanation, law_name, law_article, source_url, law_version_date,
        is_prime, law_id, primary_law_article_id, verified_at, needs_review, is_published
      ) values (
        v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation, r.law_name, r.law_article,
        nullif(r.source_url, ''), nullif(r.law_version_date, '')::date, coalesce(r.is_prime, false), v_law_id, v_article_id,
        now(), false, true
      ) returning id into v_question_id;
    else
      update public.questions
      set category_id = v_category_id,
          subcategory_id = v_subcategory_id,
          difficulty = r.difficulty::public.difficulty,
          explanation = r.explanation,
          law_name = r.law_name,
          law_article = r.law_article,
          source_url = nullif(r.source_url, ''),
          law_version_date = nullif(r.law_version_date, '')::date,
          is_prime = coalesce(r.is_prime, false),
          law_id = v_law_id,
          primary_law_article_id = v_article_id,
          verified_at = coalesce(verified_at, now()),
          needs_review = false,
          is_published = true,
          updated_at = now()
      where id = v_question_id;
    end if;

    delete from public.question_options where question_id = v_question_id;
    insert into public.question_options(question_id, option_text, is_correct, sort_order)
    values
      (v_question_id, r.option_a, r.correct_option = 'A', 1),
      (v_question_id, r.option_b, r.correct_option = 'B', 2),
      (v_question_id, r.option_c, r.correct_option = 'C', 3),
      (v_question_id, r.option_d, r.correct_option = 'D', 4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update
    set is_primary = true;
  end loop;
end $$;
